export default {
  components: {

  },
  data() {
    return {
      drop: false,
      curSelect: 0,
      menuDrop: true,
      UsersNumber: 0,
      AnimeNumber: 0,
      EpsNumber: 0,
      Cetagory: [
        {
          Name: '+13',
          Active: false,
        },
        {
          Name: '+17',
          Active: false,
        },
        {
          Name: '+20',
          Active: false,
        },
        {
          Name: 'Shounen',
          Active: false,
        },
        {
          Name: 'Seinen',
          Active: false,
        },
        {
          Name: 'Shoujo',
          Active: false,
        },
        {
          Name: 'Josei',
          Active: false,
        },
        {
          Name: 'Comedy',
          Active: false,
        },
        {
          Name: 'Harem',
          Active: false,
        },
        {
          Name: 'Horror',
          Active: false,
        },
        {
          Name: 'Ecchi',
          Active: false,
        },
        {
          Name: 'Supernatural',
          Active: false,
        },
        {
          Name: 'Slice of Life',
          Active: false,
        },
        {
          Name: 'Issekai',
          Active: false,
        },
      ],
      Users: [],
      image_preview: '',
      Sliders: [],
      deleteMessage: false,
      deleteUrl: '',
      deleteId: 0,
      addSlider: false,
      addSliderName: '',
    };
  },
  methods: {
    Calc() {
      let C = 0;
      let Cur = 1;
      for (let i = 0; i < 14; i += 1) {
        if (this.Cetagory[i].Active) {
          C += Cur;
        }
        Cur *= 2;
      }
      return C;
    },
    previewFiles(event) {
      const input = event.target;
      const file = input.files;
      if (file && file[0]) {
        const reader = new FileReader();
        reader.onload = (e) => {
          this.image_preview = e.target.result;
        };
        reader.readAsDataURL(file[0]);
        this.$emit('input', file[0]);
      }
    },
    del() {
      this.axios.get(this.deleteUrl + this.deleteId);
      if (this.deleteUrl.includes('slider')) {
        this.axios.get('http://localhost/anime/get_slider.php').then((response) => {
          this.Sliders = response.data;
        });
      }
    },
    slideAdd() {
      this.axios.get(`http://localhost/anime/add_slider.php?animename=${this.addSliderName} `);
      this.axios.get('http://localhost/anime/get_slider.php').then((response) => {
        this.Sliders = response.data;
      });
    },
  },
  created() {
    this.axios.get('http://localhost/anime/get_numbers.php').then((response) => {
      // console.log(response);
      this.UsersNumber = response.data[0];
      this.AnimeNumber = response.data[1];
      this.EpsNumber = response.data[2];
    });
    this.axios.get('http://localhost/anime/get_slider.php').then((response) => {
      this.Sliders = response.data;
    });
    this.axios.get('http://localhost/anime/All_users.php').then((response) => {
      this.Users = response.data;
    });
  },
};
</script>

