<template>
  <div class="login-page">
    <div class="form-card">
      <div class="form-logo">
        <img src="@/assets/logo.png" alt />
      </div>
      <p v-if="loginError">Email or Password is Incorrect</p>
      <form class="the-form" @submit.prevent="login()">
        <input type="email" placeholder="Enter Your Email" class="text-input" name="em" v-model="email"/>
        <input type="password" placeholder="Enter Your Passowrd" class="text-input" name="pa" v-model="pass"/>
        <input type="submit" value="login">
      </form>
    </div>

    <AppFooter />
  </div>
</template>

<script>
import AppFooter from '@/components/AppFooter.vue';
/* eslint max-len: ["error", { "code": 200 }] */
/* eslint-disable global-require */
/* eslint no-restricted-globals: ["error", "event"] */
export default {
  name: 'Login',
  components: {
    AppFooter,
  },
  data() {
    return {
      email: '',
      pass: '',
      loginError: false,
    };
  },
  created() {
    this.axios.get('http://localhost/anime/check_login.php')
      .then((response) => {
        const res = response.data;
        if (res) {
          location = 'http://localhost/anime/anime/dist/';
        }
      });
  },
  methods: {
    login() {
      this.axios.get('http://localhost/anime/login.php', {
        params: {
          em: this.email,
          pa: this.pass,
        },
      }).then((response) => {
        const res = response.data;
        if (res) {
          location = 'http://localhost/anime/anime/dist/';
        } else {
          this.loginError = true;
        }
      });
    },
  },
};
</script>

