import Vue from 'vue';
import VueRouter from 'vue-router';
import Home from '../views/Home.vue';
import Login from '../views/Login.vue';
import Register from '../views/Register.vue';
import AnimeList from '../views/AnimeList.vue';
import Settings from '../views/Settings.vue';
import AnimePage from '../views/AnimePage.vue';
import WatchPage from '../views/WatchPage.vue';
import Dashboard from '../views/Dashboard.vue';
import LastEps from '../views/LastEps.vue';
import NewestAnimes from '../views/NewestAnimes.vue';

Vue.use(VueRouter);

// {
//   path: '/about',
//   name: 'About',
//   // route level code-splitting
//   // this generates a separate chunk (about.[hash].js) for this route
//   // which is lazy-loaded when the route is visited.
//   component: () => import(/* webpackChunkName: "about" */ '../views/About.vue'),
// },


const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home,
    meta: {
      name: 'viewport',
      content: 'width=device-width,initial-scale=1.0',
    },
  },
  {
    path: '/login',
    name: 'Login',
    component: Login,
    // meta: {
    //   title: 'AnimeSYRIA | Home',
    // },

  },
  {
    path: '/register',
    name: 'Register',
    component: Register,
  },
  {
    path: '/anime-list',
    name: 'AnimeList',
    component: AnimeList,
  },
  {
    path: '/settings',
    name: 'Settings',
    component: Settings,
  },
  {
    path: '/anime-page/:Name',
    name: 'AnimePage',
    component: AnimePage,
  },
  {
    path: '/watch-page/:Name/:Number',
    name: 'WatchPage',
    component: WatchPage,
  },
  {
    path: '/dashboard',
    name: 'Dashboard',
    component: Dashboard,
  },
  {
    path: '/last-eps/:num',
    name: 'LastEps',
    component: LastEps,
  },
  {
    path: '/new-animes/:num',
    name: 'NewestAnimes',
    component: NewestAnimes,
  },
];

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes,
});

export default router;
