        {
          Name: 'yu-gi-oh',
          Image: require('../assets/posters/yu-gi-oh.jpeg'),
          Link: '#',
          Rating: 0,
          Category: 8,
        },
      ],
      AgeFilterMask: 0,
      TypeFilterMask: 0,
      FilterName: '',
    };
  },
  components: {
    AppFooter,
  },
  computed: {
    GetAnimes() {
      /* eslint no-bitwise: ["error", { "allow": ["&"] }] */
      const x = this.AgeFilterMask - '0';
      const n = this.FilterName;
      if (x === 0) {
        if (this.FilterName === '') {
          return this.AllAnime;
        }
        return this.AllAnime.filter((anime) => anime.Name.includes(n));
      }
      if (this.FilterName === '') {
        return this.AllAnime.filter((anime) => (anime.Category & x));
      }
      return this.AllAnime.filter((anime) => ((anime.Category & x) && anime.Name.includes(n)));
    },
  },
  methods: {
    GetCetagotys(x) {
      const Cetagory = ['+13', '+17', '+20', 'Shounen', 'Seinen', 'Shoujo', 'Josei', 'Comedy', 'Harem', 'Horror', 'Ecchi', 'Supernatural', 'Slice of Life', 'Issekai'];
      const Res = [];
      let Cur = 1;
      for (let i = 0; i < 14; i += 1) {
        if ((Cur & x)) {
          Res.push(Cetagory[i]);
        }
        Cur *= 2;
      }
      return Res;
    },
  },
};
/* eslint-enable global-require */

