<template>
  <div class="last-eps-page">
    <div class="card">
        <div class="bar">
          <span>{{ CardName }}</span>
        </div>
      <div class="epsoids">
        <div class="eps" v-for='(anime,index) in Animes' :key="index">
          <router-link :to='"/anime-page/" + anime[1]'>
            <img :src="anime[2]" alt />
            <span class="name">{{anime[1]}}</span>
            <span class="views">{{ anime[4] }}</span>
            <span class="rate">&#10026; {{ anime[3] }}</span>
          </router-link>
        </div>
      </div>
      <div class="pages">
        <span v-for="(p,i) in pages" :key="i" :style="[i+1==num ? {backgroundColor: '#1e9393'} : {backgroundColor: '#164543'} ]" @click="toPage(i+1)"> {{p}} </span>
      </div>
    </div>
  </div>
</template>

<script>
/* eslint max-len: ["error", { "code": 300 }] */
/* eslint-disable */

export default {
  data() {
    return {
      num: 1,
      CardName: 'Newest Animes',
      Animes: [],
      pages: [1, 2, 3],
    };
  },
  created() {
    this.load();
  },
  methods: {
    load() {
      this.num = this.$route.params.num;
      this.axios.get(`http://localhost/anime/get_new_animes.php?from=${this.num * 4 - 4}&to=${this.num * 4}`).then((response) => {
        this.Animes = response.data;
      });
    },
    toPage(x) {
      const y = `/new-animes/${x}`;
      this.$router.push(y);
    },
  },
  watch: {
    $route(to, from) {
      this.num = to.params.num;
      this.load();
    }
  },
};
</script>

